mapper.select:
select id, follower_id, following_id, created_datetime
from tbl_follow
where follower_id = #{followerId} and following_id = #{followingId}

select m.id, m.member_nickname, m.member_handle,
       (select fi.file_name from tbl_member_profile_file mpf
           join tbl_file fi on mpf.id = fi.id
        where mpf.member_id = m.id and mpf.profile_image_type = 'profile'
        limit 1) as file_name
from tbl_member m
where m.id != #{memberId}
  and m.id not in (
      select f.following_id from tbl_follow f where f.follower_id = #{memberId}
  )
  and m.id not in (
      select bl.blocked_id from tbl_block bl where bl.blocker_id = #{memberId}
  )
order by m.id desc
limit 3
